import cv2 import numpy as np # 读取图像 img=cv2.imread('lena.jpg') # 定义平移矩阵，这里将图像向右移动 100 像素，向下移动 50 像素 M=np.float32([[1,0,100],[0,1,50]]) # 对图像进行平移变换 dst=cv2.warpAffine(img,M,(img.shape[1]+100,img.shape[0]+50)) # 显示平移后的图像 cv2.imshow('image',dst) cv2.waitKey(0) cv2.destroyAllWindows()
要旋转图像，可以使用cv2.getRotationMatrix2D(）函数定义旋转矩阵，然后将其与原始图像进行矩阵乘法运算，代码如下：import cv2 # 读取图像 img=cv2.imread('lena.jpg') # 定义旋转矩阵，这里将图像顺时针旋转 45 度 M=cv2.getRotationMatrix2D((img.shape[1]/2,img.shape[0]/2),- 45,1) # 对图像进行旋转变换 dst=cv2.warpAffine(img,M,(img.shape[1],img.shape[0])) # 显示旋转后的图像 cv2.imshow('image',dst) cv2.waitKey(0) cv2.destroyAllWindows()
